#!/usr/bin/env python3
# Generate the GoalOS Proof Gradient Sovereign experience as an additive overlay.
# The canonical website source is never edited. This script operates only on the
# transient site directory produced by the existing v86 builder.
from __future__ import annotations
import argparse,csv,hashlib,html,json,re,sys
from pathlib import Path
from typing import Any

START='<!-- GOALOS_PROOF_GRADIENT_SOVEREIGN_START -->'
END='<!-- GOALOS_PROOF_GRADIENT_SOVEREIGN_END -->'
STYLE_START='<!-- GOALOS_PROOF_GRADIENT_SOVEREIGN_STYLE_START -->'
STYLE_END='<!-- GOALOS_PROOF_GRADIENT_SOVEREIGN_STYLE_END -->'
PAGE='proof-gradient-challenge.html'
CANONICAL='0xA61a3B3a130a9c20768EEBF97E21515A6046a1fA'
FORBIDDEN_PUBLIC=('third-party competitor','competitor comparison',' versus ',' vs. ')

def fail(m): raise RuntimeError(m)
def load(p):
    try:return json.loads(p.read_text(encoding='utf-8'))
    except Exception as e:fail(f'cannot read {p}: {e}')
def dump(p,v):p.parent.mkdir(parents=True,exist_ok=True);p.write_text(json.dumps(v,indent=2,ensure_ascii=False)+'\n',encoding='utf-8')
def sha(p):return hashlib.sha256(p.read_bytes()).hexdigest()
def esc(v):return html.escape(str(v),quote=True)

def validate(c,d):
    if d.get('chainId')!=1:fail('Mainnet data must use chainId 1')
    if d.get('canonicalAgialpha','').lower()!=CANONICAL.lower():fail('wrong canonical AGIALPHA')
    if d.get('goalosCreatedContractCount')!=48:fail('expected 48 GoalOS-created contracts')
    if d.get('verification',{}).get('verified')!=48 or d.get('verification',{}).get('failed')!=0:fail('expected 48 verified and 0 failed')
    if d.get('deploymentStatus')!='CONFIGURED':fail('Mainnet deployment is not CONFIGURED')
    if d.get('phaseBGrantCount')!=14:fail('expected 14 configured grants')
    if d.get('postcheck',{}).get('status')!='PASSED' or d.get('postcheck',{}).get('checkedContracts')!=48:fail('postcheck does not cover 48 contracts')
    names={x['name'] for x in d['contracts']}
    missing=[x['contractName'] for x in c['proofRoute'] if x['contractName'] not in names]
    if missing:fail('unknown proof-route contracts: '+', '.join(missing))
    blob=json.dumps(c).lower()
    for term in FORBIDDEN_PUBLIC:
        if term in blob:fail(f'public competitor reference prohibited: {term}')

