def page(c,d):
    contracts=[x for x in d['contracts'] if x['goalosCreated']]
    cats=['all']+sorted({x['category'] for x in contracts})
    chain=''.join(f"<article class='pgs-step'><b>{i:02d}</b><small>{esc(x['stage'])}</small><h3>{esc(x['title'])}</h3><p>{esc(x['copy'])}</p></article>" for i,x in enumerate(c['proofChain'],1))
    laws=''.join(f"<article class='pgs-law'>{esc(x)}</article>" for x in c['constitution'])
    accept=''.join(f"<li>{esc(x)}</li>" for x in c['acceptance'])
    hacks=''.join(f"<li>{esc(x)}</li>" for x in c['rewardHackTests'])
    route=''.join(f"<article class='pgs-route-item'><b>{x['sequence']:02d}</b><div><h3>{esc(x['stage'])} · {esc(x['contractName'])}</h3><p>{esc(x['purpose'])}</p></div><a href='https://etherscan.io/address/{esc(next(y['address'] for y in d['contracts'] if y['name']==x['contractName']))}' target='_blank' rel='noreferrer'>Etherscan ↗</a></article>" for x in c['proofRoute'])
    allocations=''.join(f"<div><span>{esc(x['label'])}</span><strong>{x['share']}%</strong></div>" for x in c['settlement'])
    filters=''.join(f"<button class='pgs-filter{' active' if i==0 else ''}' type='button' data-filter='{esc(x)}'>{esc('All 48' if x=='all' else x.upper())}</button>" for i,x in enumerate(cats))
    cards=''.join(f"<article class='pgs-contract' data-category='{esc(x['category'])}' data-search='{esc((x['name']+' '+x['address']+' '+x['purpose']).lower())}'><div class='pgs-contract-top'><span class='pgs-tag'>{esc(x['category'].upper())}</span><a href='{esc(x['etherscanUrl'])}' target='_blank' rel='noreferrer'>Etherscan ↗</a></div><h3>{esc(x['name'])}</h3><p>{esc(x['purpose'])}</p><code>{esc(x['address'])}</code><button class='pgs-copy' type='button' data-copy='{esc(x['address'])}'>Copy address</button></article>" for x in contracts)
    mission2=''.join(f"<li>{esc(x)}</li>" for x in c['mission2']['requirements'])
    boundary=''.join(f"<li>{esc(x)}</li>" for x in c['claimBoundary'])
    nodes=['OBJECTIVE','EXPERIMENT','EVIDENCE','REPLAY','DECISION','CHRONICLE']
    node_html=''.join(f"<div class='pgs-node'>{x}</div>" for x in nodes)
    return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{esc(c['title'])} — GoalOS AGIALPHA Ascension</title><meta name="description" content="{esc(c['subtitle'])}"><link rel="canonical" href="https://montrealai.github.io/goalos-agialpha-ascension/{PAGE}"><link rel="stylesheet" href="assets/goalos-v86-preserve.css">{critical_css()}</head><body class="pgs-body"><a class="pgs-skip" href="#main">Skip to content</a><nav class="pgs-nav"><div class="pgs-shell pgs-navin"><a class="pgs-brand" href="index.html">GoalOS <span>AGIALPHA</span></a><div class="pgs-navlinks"><a href="#mission">Mission</a><a href="#constitution">Constitution</a><a href="#mainnet">Mainnet</a><a href="#contracts">Contracts</a><a href="mission-os.html">Mission OS</a></div></div></nav><main id="main"><section class="pgs-hero"><div class="pgs-shell pgs-hero-grid"><div><span class="pgs-kicker">{esc(c['kicker'])}</span><h1>THE PROOF <span>GRADIENT</span></h1><p class="pgs-lead">{esc(c['subtitle'])}</p><div class="pgs-manifesto">{esc(c['manifesto'])}</div><p>{esc(c['publicThesis'])}</p><div class="pgs-actions"><a class="pgs-btn primary" href="#mission">Enter Public Mission 001</a><a class="pgs-btn" href="#mainnet">Inspect the Mainnet substrate</a><a class="pgs-btn" href="{esc(d['releaseUrl'])}" target="_blank" rel="noreferrer">Open the release ↗</a></div></div><div class="pgs-constellation" aria-label="Proof Gradient institutional chain"><div class="pgs-orbit"></div><div class="pgs-core"><div>GoalOS<span>AIM · ACT · PROVE · EVOLVE</span></div></div>{node_html}</div></div></section>
<section class="pgs-section deep" id="constitution"><div class="pgs-shell"><div class="pgs-heading"><span class="pgs-eyebrow">The constitution</span><h2>Intelligence may propose. Proof decides what propagates.</h2><p>A public operating standard for autonomous work: evidence before acceptance, replay before settlement, rollback before scale.</p></div><div class="pgs-constitution">{laws}</div></div></section>
<section class="pgs-section light"><div class="pgs-shell"><div class="pgs-heading"><span class="pgs-eyebrow">The full chain</span><h2>From objective to reusable capability—without deleting the failures.</h2><p>The institution publishes the path, not only the destination.</p></div><div class="pgs-chain">{chain}</div></div></section>
<section class="pgs-section deep" id="mission"><div class="pgs-shell"><div class="pgs-heading"><span class="pgs-eyebrow">Public Proof Mission 001</span><h2>No result is predeclared. The acceptance standard is.</h2><p>{esc(c['objective'])}</p></div><div class="pgs-mission-grid"><article class="pgs-panel"><span class="pgs-eyebrow">Acceptance standard</span><h3>What must survive</h3><ul class="pgs-list">{accept}</ul></article><article class="pgs-panel"><span class="pgs-eyebrow">Adversarial evaluator</span><h3>What must be rejected</h3><ul class="pgs-list">{hacks}</ul></article></div><div class="pgs-metrics"><article class="pgs-metric"><strong>{c['missionBudget']['candidatePatches']}</strong><span>maximum candidate patches</span></article><article class="pgs-metric"><strong>{c['missionBudget']['gpuHours']}h</strong><span>maximum GPU budget</span></article><article class="pgs-metric"><strong>2×</strong><span>independent replay operators</span></article><article class="pgs-metric"><strong>72h</strong><span>public challenge window</span></article></div></div></section>
<section class="pgs-section light" id="mainnet"><div class="pgs-shell"><div class="pgs-heading"><span class="pgs-eyebrow">Ethereum Mainnet substrate</span><h2>The institutional route is deployed, configured, and source-verified.</h2><p>GoalOS records commitments, evidence, replay, evaluation, selection, settlement, memory, reuse, and rollback through a public contract constellation.</p></div><div class="pgs-metrics"><article class="pgs-metric" style="background:#071522"><strong>48</strong><span>GoalOS-created contracts</span></article><article class="pgs-metric" style="background:#071522"><strong>48/48</strong><span>recorded source-verified</span></article><article class="pgs-metric" style="background:#071522"><strong>0</strong><span>verification failures</span></article><article class="pgs-metric" style="background:#071522"><strong>14/14</strong><span>configuration grants active</span></article></div><div class="pgs-route" style="margin-top:2rem">{route}</div></div></section>
<section class="pgs-section gold"><div class="pgs-shell pgs-settlement"><div class="pgs-ring" aria-label="Illustrative conditional settlement allocation"></div><div><span class="pgs-eyebrow" style="color:#071522">Proof economy</span><h2 style="font-size:clamp(2.4rem,5vw,4.5rem);letter-spacing:-.055em;margin:.8rem 0">Accepted proof becomes economically consequential.</h2><p style="font-size:1.1rem;line-height:1.65">A fixed AGIALPHA bounty may settle only after acceptance and challenge. The allocation recognizes execution, ancestry, validation, replay, falsification, and Chronicle packaging.</p><div class="pgs-alloc">{allocations}</div></div></div></section>
<section class="pgs-section deep"><div class="pgs-shell"><div class="pgs-heading"><span class="pgs-eyebrow">Mission 002</span><h2>{esc(c['mission2']['title'])}</h2><p>{esc(c['mission2']['copy'])}</p></div><div class="pgs-panel"><ul class="pgs-list">{mission2}</ul></div></div></section>
<section class="pgs-section deep" id="contracts"><div class="pgs-shell"><div class="pgs-heading"><span class="pgs-eyebrow">Mainnet contract atlas</span><h2>Inspect the 48-contract proof substrate.</h2><p>Search the deployed GoalOS contracts and open any address directly on Etherscan.</p></div><div class="pgs-contract-tools"><input class="pgs-input" id="pgs-search" type="search" placeholder="Search contract, address, or purpose" aria-label="Search contracts"><div class="pgs-filters">{filters}</div></div><div class="pgs-contract-grid" id="pgs-contract-grid">{cards}</div></div></section>
<section class="pgs-section deep"><div class="pgs-shell"><div class="pgs-boundary"><span class="pgs-eyebrow">Claim boundary</span><h2>Grand ambition. Exact language.</h2><ul class="pgs-list">{boundary}</ul><div class="pgs-downloads"><a href="downloads/proof-gradient/goalos-mainnet-contract-addresses.csv">Addresses CSV</a><a href="downloads/proof-gradient/proof-gradient-mainnet-map.json">Mainnet map JSON</a><a href="downloads/proof-gradient/public-proof-mission-001.json">Mission JSON</a><a href="{esc(c['repositoryUrl'])}" target="_blank" rel="noreferrer">GitHub repository ↗</a></div></div></div></section></main><footer class="pgs-footer"><div class="pgs-shell pgs-footerin"><strong>GoalOS AGIALPHA Ascension · The Proof Gradient</strong><span>Ethereum Mainnet · Not externally audited</span></div></footer><div class="pgs-toast" id="pgs-toast" role="status" aria-live="polite">Address copied</div><script src="assets/goalos-v86-dynamic-ai.js" defer></script><script>
(()=>{{const q=document.getElementById('pgs-search'),cards=[...document.querySelectorAll('.pgs-contract')],filters=[...document.querySelectorAll('.pgs-filter')];let active='all';function render(){{const term=(q.value||'').trim().toLowerCase();cards.forEach(c=>{{const ok=(active==='all'||c.dataset.category===active)&&(!term||c.dataset.search.includes(term));c.hidden=!ok}})}}q.addEventListener('input',render);filters.forEach(b=>b.addEventListener('click',()=>{{active=b.dataset.filter;filters.forEach(x=>x.classList.toggle('active',x===b));render()}}));const toast=document.getElementById('pgs-toast');document.querySelectorAll('[data-copy]').forEach(b=>b.addEventListener('click',async()=>{{try{{await navigator.clipboard.writeText(b.dataset.copy);toast.classList.add('show');setTimeout(()=>toast.classList.remove('show'),1400)}}catch(e){{}}}}));}})();
</script></body></html>'''

def home_style():
 return f'''{STYLE_START}<style>
.pgs-home{{position:relative;overflow:hidden;padding:6.8rem 0;background:radial-gradient(circle at 76% 36%,rgba(89,231,255,.17),transparent 24%),radial-gradient(circle at 18% 58%,rgba(166,146,255,.12),transparent 27%),linear-gradient(145deg,#06111d,#0b2031);color:#eef7fb;border-top:1px solid rgba(255,255,255,.12);border-bottom:1px solid rgba(255,255,255,.12)}}.pgs-home:before{{content:"";position:absolute;inset:0;background-image:linear-gradient(rgba(255,255,255,.032) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.032) 1px,transparent 1px);background-size:48px 48px;mask-image:linear-gradient(90deg,#000,transparent)}}.pgs-home-in{{position:relative;z-index:1;width:min(1180px,calc(100% - 2rem));margin:auto;display:grid;grid-template-columns:1.1fr .9fr;gap:3rem;align-items:center}}.pgs-home-kicker{{text-transform:uppercase;letter-spacing:.14em;color:#f4c96b;font-size:.72rem;font-weight:950}}.pgs-home h2{{font-size:clamp(3.1rem,7vw,6.5rem);line-height:.88;letter-spacing:-.065em;margin:.8rem 0 1.2rem}}.pgs-home h2 span{{color:transparent;background:linear-gradient(90deg,#59e7ff,#fff 52%,#f4c96b);background-clip:text}}.pgs-home p{{font-size:1.17rem;line-height:1.65;color:#cfe1e9;max-width:700px}}.pgs-home-actions{{display:flex;gap:.7rem;flex-wrap:wrap;margin-top:1.6rem}}.pgs-home-actions a{{padding:.78rem 1rem;border:1px solid rgba(255,255,255,.22);border-radius:999px;text-decoration:none;font-weight:900;color:#fff}}.pgs-home-actions a:first-child{{background:#59e7ff;color:#06111d;border-color:transparent}}.pgs-home-orb{{position:relative;aspect-ratio:1;border-radius:50%;border:1px solid rgba(255,255,255,.16);display:grid;place-items:center;background:radial-gradient(circle,rgba(89,231,255,.18),transparent 35%),rgba(255,255,255,.025);box-shadow:inset 0 0 70px rgba(89,231,255,.07)}}.pgs-home-orb:before,.pgs-home-orb:after{{content:"";position:absolute;border-radius:50%;border:1px solid rgba(255,255,255,.15)}}.pgs-home-orb:before{{inset:11%}}.pgs-home-orb:after{{inset:25%;border-color:rgba(244,201,107,.26)}}.pgs-home-core{{width:36%;aspect-ratio:1;border-radius:50%;display:grid;place-items:center;text-align:center;background:radial-gradient(circle at 35% 30%,#fff,#59e7ff 40%,#887aff 80%);color:#06111d;font-weight:1000;box-shadow:0 0 60px rgba(89,231,255,.38);z-index:2}}.pgs-home-stats{{display:grid;grid-template-columns:repeat(2,1fr);gap:.65rem;margin-top:1.4rem}}.pgs-home-stat{{padding:.9rem;border:1px solid rgba(255,255,255,.14);border-radius:16px;background:rgba(255,255,255,.045)}}.pgs-home-stat strong{{display:block;font-size:1.55rem;color:#fff}}.pgs-home-stat span{{font-size:.78rem;color:#abc0cc}}@media(max-width:820px){{.pgs-home-in{{grid-template-columns:1fr}}.pgs-home-orb{{max-width:460px;margin:auto;width:100%}}}}@media(max-width:520px){{.pgs-home{{padding:4.6rem 0}}.pgs-home h2{{font-size:3.6rem}}.pgs-home-actions a{{width:100%;text-align:center}}}}
</style>{STYLE_END}'''

def home_section():
 return f'''{START}<section class="pgs-home"><div class="pgs-home-in"><div><div class="pgs-home-kicker">Public Proof Mission 001 · Ethereum Mainnet</div><h2>THE PROOF <span>GRADIENT</span></h2><p><strong>Where autonomous work earns the right to become capability.</strong> GoalOS publishes the complete chain from objective and experiment to falsification, replay, validator decision, settlement, Chronicle memory, and controlled reuse.</p><div class="pgs-home-stats"><div class="pgs-home-stat"><strong>48 / 48</strong><span>GoalOS-created contracts recorded verified</span></div><div class="pgs-home-stat"><strong>0 failed</strong><span>Mainnet verification failures</span></div><div class="pgs-home-stat"><strong>14 / 14</strong><span>configuration grants active</span></div><div class="pgs-home-stat"><strong>Mission 001</strong><span>result not predeclared</span></div></div><div class="pgs-home-actions"><a href="{PAGE}">Enter the Proof Gradient</a><a href="{PAGE}#mainnet">Inspect the Mainnet substrate</a></div></div><div class="pgs-home-orb"><div class="pgs-home-core">AIM<br>ACT<br>PROVE<br>EVOLVE</div></div></div></section>{END}'''

def replace_marked(text,start,end,repl):return re.sub(re.escape(start)+r'.*?'+re.escape(end),repl,text,flags=re.S)
def inject(p):
 raw=p.read_text(encoding='utf-8')
 if STYLE_START in raw:raw=replace_marked(raw,STYLE_START,STYLE_END,home_style())
 else:raw=raw.replace('</head>',home_style()+'\n</head>',1)
 if START in raw:raw=replace_marked(raw,START,END,home_section())
 else:
  anchor="<section class='asi-section white'><div class='asi-wrap'><div class='asi-kicker'>World-launch command pages</div>"
  if anchor not in raw:fail('homepage insertion anchor not found')
  raw=raw.replace(anchor,home_section()+'\n'+anchor,1)
 p.write_text(raw,encoding='utf-8')

def downloads(site,c,d):
 out=site/'downloads'/'proof-gradient';out.mkdir(parents=True,exist_ok=True)
 with (out/'goalos-mainnet-contract-addresses.csv').open('w',newline='',encoding='utf-8') as f:
  w=csv.DictWriter(f,fieldnames=['name','address','category','purpose','goalos_created','verification_status','etherscan_url']);w.writeheader()
  for x in d['contracts']:w.writerow({'name':x['name'],'address':x['address'],'category':x['category'],'purpose':x['purpose'],'goalos_created':str(x['goalosCreated']).lower(),'verification_status':x['verificationStatus'],'etherscan_url':x['etherscanUrl']})
 dump(out/'proof-gradient-mainnet-map.json',{'schemaVersion':'1.0','missionId':c['missionId'],'releaseTag':d['releaseTag'],'chainId':1,'canonicalAgialpha':d['canonicalAgialpha'],'deploymentStatus':d['deploymentStatus'],'verification':d['verification'],'postcheck':d['postcheck'],'contracts':d['contracts'],'proofRoute':c['proofRoute'],'claimBoundary':c['claimBoundary']})
 dump(out/'public-proof-mission-001.json',c)

def sitemap(p):
 url='https://montrealai.github.io/goalos-agialpha-ascension/'+PAGE
 raw=p.read_text(encoding='utf-8') if p.exists() else "<?xml version='1.0' encoding='UTF-8'?><urlset xmlns='http://www.sitemaps.org/schemas/sitemap/0.9'></urlset>"
 if url not in raw:raw=raw.replace('</urlset>',f'<url><loc>{url}</loc></urlset>')
 p.write_text(raw,encoding='utf-8')

def main():
 ap=argparse.ArgumentParser();ap.add_argument('--site',default='site');ap.add_argument('--content',default='content/proof-gradient-sovereign.json');ap.add_argument('--mainnet',default='data/mainnet/v4.4.0-mainnet-2026-06-21.json');a=ap.parse_args()
 repo=Path.cwd();site=repo/a.site;c=load(repo/a.content);d=load(repo/a.mainnet);validate(c,d)
 if not (site/'index.html').exists():fail('build the canonical v86 site first')
 (site/PAGE).write_text(page(c,d),encoding='utf-8');inject(site/'index.html');downloads(site,c,d);sitemap(site/'sitemap.xml')
 status=load(site/'site-status.json') if (site/'site-status.json').exists() else {};status['proofGradient']={'edition':'SOVEREIGN_V3','missionId':c['missionId'],'page':PAGE,'goalosContracts':48,'verified':48,'failed':0,'publicNetworkTransactionSent':False};dump(site/'site-status.json',status)
 dump(site/'qa'/'proof-gradient-sovereign-build.json',{'status':'PASS','mode':'ADDITIVE_GENERATED_SITE_OVERLAY','canonicalSourceModified':False,'newPage':PAGE,'mainnetDataSha256':sha(repo/a.mainnet),'goalosCreatedContracts':48,'verified':48,'failed':0,'phaseBGrants':14,'publicCompetitorReferences':0,'publicNetworkTransactionSent':False})
 print(json.dumps({'status':'PASS','page':PAGE,'goalosContracts':48,'verified':48,'failed':0},indent=2));return 0
if __name__=='__main__':
 try:raise SystemExit(main())
 except Exception as e:print('ERROR:',e,file=sys.stderr);raise SystemExit(1)
